int solveQuery(int start, int end, vector<int> arr) {
    int count = 0;
    unordered_map<int, int> frequency;
    for (int i = start; i <= end; i++) {
        int element = arr[i];
        if (frequency.find(element) != frequency.end()) {
            frequency[element] += 1;
        } else {
            frequency[element] = 1;
        }
    }
    for (int x : frequency) {
        if (x == frequency[x]) {
            count++;
        }
    }
    return count;
}

