int HalfDiagonalSums ( std::vector <std::vector <int> >& mat , int n ) {
    int diag1_left = 0, diag1_right = 0, diag2_left = 0, diag2_right = 0;
    for ( int i = 0 ; i < n ; i++ ) {
        if ( i < n / 2 ) {
            diag1_left += mat [ i ] [ i ];
            diag2_left += mat [ n - i - 1 ] [ i ];
        }
        else if ( i > n / 2 ) {
            diag1_right += mat [ i ] [ i ];
            diag2_right += mat [ n - i - 1 ] [ i ];
        }
    }
    return ( diag1_left == diag2_right && diag2_right == diag2_left && diag1_right == diag2_left && diag2_right == mat [ n / 2 ] [ n / 2 ] );
}

