bool areConsecutive(vector<int> arr, int n) {
    if (n < 1) {
        return false;
    }
    int Min = arr[0], Max = arr[0];
    for (int i = 0; i < n; i++) {
        Min = min(Min, arr[i]);
        Max = max(Max, arr[i]);
    }
    if (Max - Min + 1 == n) {
        vector<bool> visited(n, false);
        for (int i = 0; i < n; i++) {
            if (visited[arr[i] - Min]) {
                return false;
            }
            visited[arr[i] - Min] = true;
        }
        return true;
    }
    return false;
}

