    std::string binary = "";
    int Integral = (int)num;
    float fractional = num - Integral;
    while(Integral > 0){
        int rem = Integral % 2;
        binary += std::to_string(rem);
        Integral /= 2;
    }
    binary = binary.substr(binary.size()-1);
    binary += '.';
    while(k_prec > 0){
        fractional *= 2;
        int fract_bit = (int)fractional;
        if(fract_bit == 1){
            fractional -= fract_bit;
            binary += '1';
        }
        else{
            binary += '0';
        }
        k_prec -= 1;
    }
    return binary;
}

