    sum[0] = 0;
    for (int i = 1; i <= n; i++) {
        sum[i] = sum[i-1] + arr[i-1];
    }
    std::vector<int> Q;
    std::make_heap(Q.begin(), Q.end());
    for (int i = 1; i <= n; i++) {
        for (int j = i; j <= n; j++) {
            int x = sum[j] - sum[i-1];
            if (Q.size() < k) {
                std::push_heap(Q.begin(), Q.end(), x);
            } else {
                if (Q[0] < x) {
                    std::pop_heap(Q.begin(), Q.end());
                    Q.erase(Q.end()-1);
