int lengthOfLongestAP(vector<int>& set, int n) {
    if (n <= 2) {
        return n;
    }
    int** L = new int*[n];
    for (int i = 0; i < n; i++) {
        L[i] = new int[n];
        L[i][n - 1] = 2;
    }
    int llap = 2;
    for (int i = 0; i < n; i++) {
        for (int j = i; j < n; j++) {
            L[i][j] = 2;
        }
    }
    for (int j = n - 2; j >= 0; j--) {
        int i = j - 1;
        int k = j + 1;
        while (i >= 0 && k <= n - 1) {
            if (set[i] + set[k] < 2 * set[j]) {
                k += 1;
            } else if (set[i] + set[k] > 2 * set[j]) {
                L[i][j] = 2;
                i -= 1;
            } else {
                L[i][j] = L[j][k] + 1;
                llap = max(llap, L[i][j]);
                i -= 1;
                k += 1;
            }
        }
        while (i >= 0) {
            L[i][j] = 2;
            i -= 1;
        }
    }
    return llap;
}

