int findMaxVal(vector<int>& arr, int n, int num, int maxLimit) {
    // dp[i][j] represents the maximum value of subarray ending with nums[i] such that the sum is at most j
    vector<vector<int>> dp(n + 1, vector<int>(maxLimit + 1, 0));
    // Initialize dp
    for (int i = 0; i <= n; i++) {
        dp[i][0] = 1;
    }
    // Iterate through each index
    for (int i = 0; i < n; i++) {
        for (int j = 0; j <= maxLimit; j++) {
            // Check if the current sum is less than or equal to the max limit
            if (j - arr[i] >= 0) {
                dp[i + 1][j] = max(dp[i + 1][j], dp[i][j - arr[i]]);
            }
            // Check if the current sum is greater than or equal to the max limit
            if (j + arr[i] <= maxLimit) {
                dp[i + 1][j] = max(dp[i + 1][j], dp[i][j + arr[i]]);
            }
        }
    }
    // Find the maximum value in the last row
    int maxVal = 0;
    for (int i = 0; i <= maxLimit; i++) {
        maxVal = max(maxVal, dp[n][i]);
    }
    return maxVal;
}

