    int longest_start = -1;
    int longest_end = 0;
    for (int start = 0; start < n; start++) {
        int min = numeric_limits<int>::max();
        int max = numeric_limits<int>::min();
        for (int end = start; end < n; end++) {
            int val = arr[end];
            if (val < min) {
                min = val;
