int KnapSack(int val[], int wt[], int n, int W) {
    // Create a 2-D matrix to store the values of sub-problems
    int mat[2][W + 1];
    // Initialize the first row of the matrix
    for (int j = 0; j <= W; j++) mat[0][j] = 0;
    // Initialize the first column of the matrix
    for (int i = 1; i <= n; i++) mat[i][0] = 0;
    // Fill the rest of the matrix
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= W; j++) {
            if (wt[i - 1] <= j && j - wt[i - 1] < W) {
                mat[i][j] = max(val[i - 1] + mat[i - 1][j - wt[i - 1]], mat[i - 1][j]);
            } else {
                mat[i][j] = mat[i - 1][j];
            }
        }
    }
    // Return the maximum value
    if (n % 2 == 0) {
        return mat[0][W];
    } else {
        return mat[1][W];
    }
}

