                if (j == 0) {
                    if (a[j] == b[i]) dp[i][j] = 1;
                    else dp[i][j] = 0;
                } else if (a[j] == b[i]) dp[i][j] = dp[i][j - 1] + 1;
                else dp[i][j] = dp[i][j - 1];
